var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":"SYLVIA_DELTA_NULL_NULL","text":{"KOREA":"안녕?","JPN":"ハロー。","ENG":"Hi!","TWN":"嗨？"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SYLVIA_DELTA_NULL_NULL","face":"UNIT_LAUGH"},"R":null}},"sfx":"FX_CUTSCEN_NOISE"},{"id":"L3_1","type":"dialog","speaker":"SYLVIA_DELTA_NULL_NULL","text":{"KOREA":"오랜만이야, 즐거운 코핀 친구들~!","JPN":"久しぶりね。コフィンの愉快な仲間たち～！","ENG":"Long time no see, Coffineers!","TWN":"好久不見，科芬的朋友們！"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SYLVIA_DELTA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L4_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_NULL_NULL","text":{"KOREA":"하하. 실비아 양도 건강해 보이셔서 다행입니다.","JPN":"ハハ、シルビアさんもお元気そうでなによりです。","ENG":"Haha. I’m glad to see you’ve been doing well too.","TWN":"哈哈！希爾維亞小姐看起來氣色很好呢！"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JOOSHIYOON_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"SYLVIA_DELTA_NULL_NULL","text":{"KOREA":"그래 보여? 통신 화질이 별로 안 좋은가 보네.","JPN":"そう見える？　画質があまり良くないみたいね。","ENG":"Does it look like I’m doing well? The video feed must be faulty.","TWN":"是嗎？看來通信畫質不是很好啊。"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SYLVIA_DELTA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"SYLVIA_DELTA_NULL_NULL","text":{"KOREA":"지금 눈 밑에 다크 서클이 이렇게 늘어나 있는데 말이지.","JPN":"目の下にクマがこーんなに伸びてるのにさ。","ENG":"I've got bags under my eyes so big I could probably fit my groceries in there.","TWN":"我最近黑眼圈很重呢。"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SYLVIA_DELTA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"......의외야.","JPN":"……意外。","ENG":"I must say, I’m a bit surprised.","TWN":"……真是意外。"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"지난번에는 신뢰가 어쩌고 하면서 뭐 다시는 연락 안 할 것처럼 굴더니......","JPN":"この前は信頼がどうのこうの言って、二度と連絡しない気満々に見えたのに……","ENG":"You went on about trust or whatever last time, as if you’d never reach out to us again...","TWN":"上次有人才說雙方的信任如何如何，然後說不會再跟我們聯絡了……"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"SYLVIA_DELTA_NULL_NULL","text":{"KOREA":"그랬던가? 하하, 잘 기억이 안 나네?","JPN":"そうだったかしら？　ハハ、あまり覚えてないかも。","ENG":"Did I? Haha... I’m not sure I remember...","TWN":"是嗎？記不太清楚了呢。"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SYLVIA_DELTA_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"SYLVIA_DELTA_NULL_NULL","text":{"KOREA":"뭐, 지금 같은 비상 시국에 사소한 오해 정도는 얼마든지 덮어 둘 수 있는 거니까.","JPN":"まあ、非常事態なんだし、ちょっとした誤解ぐらいはしょうがないよね。","ENG":"Anyway, I’m sure I can put some trivial misunderstanding like that aside in an emergency like this.","TWN":"現在事態緊急，那些微不足道的誤會大家就別計較了吧。"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SYLVIA_DELTA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"......뻔뻔해.","JPN":"……ふてぶてしいな。","ENG":"How shameless...","TWN":"……臉皮真厚。"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"SYLVIA_DELTA_NULL_NULL","text":{"KOREA":"유감이야. 그 아줌마라면 충분히 이해해 줬을 텐데.","JPN":"残念ね～。あのオバサンなら十分理解してくれるでしょうに。","ENG":"It’s too bad, really. I’m sure the old lady would've understood.","TWN":"真遺憾，要是那位大嬸在的話肯定可以理解的。"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SYLVIA_DELTA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"SYLVIA_DELTA_NULL_NULL","text":{"KOREA":"그러고 보니 그 아줌마는 어디에 있어? 여기엔 안 보이네?","JPN":"そういえば、あのオバサンはどこ？　見当たらないわね。","ENG":"Speaking of which, where is that lady? I don’t see her over there.","TWN":"這麼一說，那位大嬸在哪裡啊？沒來嗎？"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SYLVIA_DELTA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"HILDE_FENRIR_NULL_NULL","text":{"KOREA":"아쉽지만 이수연 부사장은 본사에서 대기 중이다.","JPN":"残念だが、カナミ副社長は本社で待機している。","ENG":"Regrettably, Vice President Lee is standing by at HQ.","TWN":"很遺憾，副總李秀妍今天在總公司。"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HILDE_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"HILDE_FENRIR_NULL_NULL","text":{"KOREA":"나중에 안부 전하도록 하지.","JPN":"後でよろしく伝えておくよ。","ENG":"I’ll tell her you said hi.","TWN":"我之後會幫妳和她問好的。"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HILDE_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"HILDE_FENRIR_NULL_NULL","text":{"KOREA":"그보다 이쪽에서 요청한 정보는 어떻게 됐지? 찾았나?","JPN":"それより、こちらから要請した情報はどうなった？　見つけたか？","ENG":"More importantly, what's the status on the intel we requested? Did you find anything?","TWN":"不說這些了，我們要求的資訊怎麼樣了？找到了嗎？"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HILDE_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"SYLVIA_DELTA_NULL_NULL","text":{"KOREA":"음...... 그거 말이지......","JPN":"うーん……あれね……","ENG":"Well... About that...","TWN":"呃……那個嘛……"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SYLVIA_DELTA_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"SYLVIA_DELTA_NULL_NULL","text":{"KOREA":"뭐, 찾긴 했어.","JPN":"まぁ、見つかってはいるんだけど。","ENG":"We did find something.","TWN":"找是找到了，但是……"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SYLVIA_DELTA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"SYLVIA_DELTA_NULL_NULL","text":{"KOREA":"국무부 쪽의 연줄을 총동원해서 전 세계 사건 기록을 탈탈 털었으니까.","JPN":"国務省のコネというコネを全部使って、世界中の事件記録を漁ったからね。","ENG":"We called in every favor stacked up with the State Department to search through all the cases across the world.","TWN":"國務部那邊動用了關係，把全世界範圍內的事件記錄都拿走了。"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SYLVIA_DELTA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"SYLVIA_DELTA_NULL_NULL","text":{"KOREA":"그런데 정말 이 정보가 이번 사건을 해결하는 데 도움이 되는 거 맞아?","JPN":"ところで、本当にこの情報が今回の事件を解決するのに役立つの？","ENG":"But are you sure this intel will help you solve this case?","TWN":"這個資訊真的有助於解決這次事件嗎？"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SYLVIA_DELTA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"SYLVIA_DELTA_NULL_NULL","text":{"KOREA":"흥미롭긴 하지만 딱히 관련 있어 보이진 않던데......","JPN":"興味深いけど、これといった関連があるようには見えなかったけどね……","ENG":"It makes an interesting read, but it doesn’t seem particularly relevant...","TWN":"雖然資料本身很有意思，但之間不像是有明確的關係……"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SYLVIA_DELTA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"HILDE_FENRIR_NULL_NULL","text":{"KOREA":"글쎄, 그건 이제부터 두고 봐야겠지.","JPN":"さあ、それは今から確認してみないとな。","ENG":"Well, we’ll have to see about that.","TWN":"這個嘛，妳之後就會知道了。"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HILDE_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"SYLVIA_DELTA_NULL_NULL","text":{"KOREA":"......재촉해서 미안하지만 지금 상황이 정말 좋지 않아.","JPN":"催促して申し訳ないけど、今は本当に厳しい状況なの。","ENG":"I’d hate to rush you, but the situation doesn’t look so good right now.","TWN":"……擅自催促有點不好意思，但是現在的情況真的不是很樂觀。"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SYLVIA_DELTA_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"SYLVIA_DELTA_NULL_NULL","text":{"KOREA":"현장 팀의 보고에 따르면 파괴된 로스트 쉽이 복원될 때마다 점점 더 강해지고 있다고 해.","JPN":"現場チームの報告によると、破壊されたロストシップが復活するたびに、ますます強化されているそうよ。","ENG":"According to our field teams, the Lost Ships are getting more powerful each time they are restored.","TWN":"據現場的隊伍報告，失落艦船每次復原後都在逐漸變強。"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SYLVIA_DELTA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L25_1","type":"dialog","speaker":"SYLVIA_DELTA_NULL_NULL","text":{"KOREA":"이대로 가면 곧 파괴가 불가능한 임계점에 도달하게 될 거야.","JPN":"このままでは、間もなく破壊不可能なレベルに到達すると思う。","ENG":"At this rate, they might reach a threshold where they become virtually indestructible soon.","TWN":"再這樣下去，會達到無法破壞的臨界點的。"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SYLVIA_DELTA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L26_1","type":"dialog","speaker":"SYLVIA_DELTA_NULL_NULL","text":{"KOREA":"예고도 없이 튀어나오는 리플레이서 놈들은 덤이고 말이지.","JPN":"オマケに、リプレイサーのやつらが前触れもなく出没してるしね。","ENG":"All that while we still got to deal with those Replacers that keep popping out of nowhere.","TWN":"而且還要算上那些一聲不響就冒出來的克隆集團。"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SYLVIA_DELTA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L27_1","type":"dialog","speaker":"HILDE_FENRIR_NULL_NULL","text":{"KOREA":".......","JPN":"……","ENG":".......","TWN":"……"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HILDE_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L28_1","type":"dialog","speaker":"SYLVIA_DELTA_NULL_NULL","text":{"KOREA":"경제 쪽은 더 심각해.","JPN":"経済の方はさらに深刻よ。","ENG":"The economic impact is even more severe.","TWN":"經濟方面更加糟糕。"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SYLVIA_DELTA_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L29_1","type":"dialog","speaker":"SYLVIA_DELTA_NULL_NULL","text":{"KOREA":"모든 태스크포스들이 로스트 쉽 파괴에 동원되고 있는 바람에 이터니움 공급량이 확 떨어졌다고.","JPN":"すべてのタスクフォースカンパニーがロストシップの破壊に動員されているせいで、\\nエタニウム供給量がガタ落ちしてるの。","ENG":"With every TASKFORCE mobilized in support of destroying the Lost Ships, Eternium supply has plummeted.","TWN":"所有的特遣勢力都被派去攻擊失落艦船了，永恆之金的供給量大幅度下降。"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SYLVIA_DELTA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L30_1","type":"dialog","speaker":"SYLVIA_DELTA_NULL_NULL","text":{"KOREA":"지금 세계 경제에 이터니움이 끼치는 영향력을 고려한다면......","JPN":"今、世界経済にエタニウムが及ぼす影響力を考えると……","ENG":"Considering the impact Eternium has on the world economy...","TWN":"試想永恆之金對世界經濟的影響，"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SYLVIA_DELTA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L31_1","type":"dialog","speaker":"SYLVIA_DELTA_NULL_NULL","text":{"KOREA":"......대공황이 올지도 몰라.","JPN":"……大恐慌が訪れるかも知れない。","ENG":"...we might be headed for a global depression.","TWN":"……會不會發生大恐慌都不知道。"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SYLVIA_DELTA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L32_1","type":"dialog","speaker":"SYLVIA_DELTA_NULL_NULL","text":{"KOREA":"정보통제를 하고 있긴 하지만 벌써부터 증시가 출렁이는 걸 보면 그것도 얼마나 갈 수 있을지.......","JPN":"情報統制はしてるけど、すでに株市場が乱高下しているから、あとどれ位持つか……","ENG":"We're trying to keep the information contained, but the stock market’s been getting jumpy already... so who knows how long we can keep that going.","TWN":"雖然我們有在控制消息，但是看股市的波動，估計撐不了多久了……"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SYLVIA_DELTA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L33_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"......그렇게 상황이 안 좋은 거야?","JPN":"……そこまで厳しい状況なの？","ENG":"Things are really that bad?","TWN":"……情況真的這麼糟糕嗎？"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L34_1","type":"dialog","speaker":"SYLVIA_DELTA_NULL_NULL","text":{"KOREA":"당연하지!","JPN":"そうよ！","ENG":"Well, duh!","TWN":"當然！"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SYLVIA_DELTA_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L35_1","type":"dialog","speaker":"SYLVIA_DELTA_NULL_NULL","text":{"KOREA":"지금 상황을 타파할 수만 있다면 난 십자로의 악마에게 무릎 꿇고 발에 키스라도 해야 할 판이라고!","JPN":"今の状況を打破できるなら、アタシは十字路で悪魔に跪いて、\\nそいつの足にキスでもなんでもするわね！","ENG":"I’d kiss the devil’s ass if it means we could make all of this go away! It’s that bad!","TWN":"要是能打破現在的局面，要我下跪舔惡魔的腳我都願意！"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SYLVIA_DELTA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L38_1","type":"dialog","speaker":"KYLE_DELTA_NULL_NULL","text":{"KOREA":"실비아 씨, 뭘 노닥거리고 있는 겁니까?","JPN":"シルビアさん、何のんびりとお喋りしているんですか？","ENG":"Goofing off again, Sylvia?","TWN":"希爾維亞小姐，妳在閒聊些什麼呢？"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SYLVIA_DELTA_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"KYLE_DELTA_NULL_NULL","face":"UNIT_IDLE"}}},"sfx":"FX_CUTSCEN_NOISE"},{"id":"L39_1","type":"dialog","speaker":"SYLVIA_DELTA_NULL_NULL","text":{"KOREA":"카, 카일? 언제 도착한 거야?","JPN":"カイル？　いつ着いたの？","ENG":"K-Kyle? When did you get back?","TWN":"凱，凱爾？你什麼時候到的？"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SYLVIA_DELTA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"KYLE_DELTA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L40_1","type":"dialog","speaker":"KYLE_DELTA_NULL_NULL","text":{"KOREA":"5분 16초 전에 귀환했습니다.","JPN":"5分16秒前に帰還しました。","ENG":"5 minutes and 16 seconds ago.","TWN":"5分16秒前回來的。"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SYLVIA_DELTA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"KYLE_DELTA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L41_1","type":"dialog","speaker":"KYLE_DELTA_NULL_NULL","text":{"KOREA":"그나저나 이런 시국에도 전화기나 붙잡고 수다 떨 정신머리가 있다니 정말 놀랍군요.","JPN":"ところで、こんな状況でも電話でおしゃべりできるなんて、驚きしかありませんね。","ENG":"You never fail to surprise me. Loafing on the phone despite the cataclysmic situation out there...","TWN":"不過現在都這種狀況了，竟然會有個神經病還有心情拿著電話聊天，太令我驚訝了。"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SYLVIA_DELTA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"KYLE_DELTA_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L42_1","type":"dialog","speaker":"KYLE_DELTA_NULL_NULL","text":{"KOREA":"하여간 요즘 젊은 것들이란...... 대체 언제 철들 겁니까?","JPN":"これだから最近の若者は……いったい、いつになったらまともになりますか？","ENG":"Like I always say, you youngsters these days are up to no good. When will you ever grow up?","TWN":"最近的年輕人……到底什麼時候才會長大啊？"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SYLVIA_DELTA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"KYLE_DELTA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L43_1","type":"dialog","speaker":"SYLVIA_DELTA_NULL_NULL","text":{"KOREA":"......야! 이 애늙은이야! 네놈이 나보다 더 어리잖아!!","JPN":"……はあ？　このませガキめ！\\nあんた、アタシより年下でしょ！！","ENG":"Hey! Don't be ridiculous! You're even younger than me!","TWN":"……喂！你這個年輕小老頭！你比我還小耶！"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SYLVIA_DELTA_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"KYLE_DELTA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L44_1","type":"dialog","speaker":"KYLE_DELTA_NULL_NULL","text":{"KOREA":"변명은 추합니다.","JPN":"言い訳するなんて、みっともないです。","ENG":"That does not justify your abhorrent behavior.","TWN":"真是難看的藉口。"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SYLVIA_DELTA_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"KYLE_DELTA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L45_1","type":"dialog","speaker":"KYLE_DELTA_NULL_NULL","text":{"KOREA":"출격 명령이 떨어졌으니 당장 튀어나오세요.","JPN":"出撃命令が出されたので、今すぐ行ってきてください。","ENG":"Now, please move out at once. The mission is go.","TWN":"出擊命令下來了，我們要立刻出動。"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SYLVIA_DELTA_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"KYLE_DELTA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L46_1","type":"dialog","speaker":"KYLE_DELTA_NULL_NULL","text":{"KOREA":"20초 드립니다.","JPN":"20秒あげましょう。","ENG":"You've got 20 seconds.","TWN":"我給妳20秒。"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SYLVIA_DELTA_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"KYLE_DELTA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L47_1","type":"dialog","speaker":"SYLVIA_DELTA_NULL_NULL","text":{"KOREA":"......또야? 나 복귀한 지 30분밖에 안 됐다고!","JPN":"……また？　アタシ、復帰してから30分しか経ってないのに！","ENG":"Again? I just got back half an hour ago!","TWN":"……又要出擊？我才回來不到半小時耶！"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SYLVIA_DELTA_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"KYLE_DELTA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L48_1","type":"dialog","speaker":"KYLE_DELTA_NULL_NULL","text":{"KOREA":"중장님 명령입니다. 뉴욕에 나타난 로스트 쉽이 방금 재생되었다고 합니다.","JPN":"中将からの命令です。\\nニューヨークに現れたロストシップがたった今再生されたそうです。","ENG":"It’s straight from the Lieutenant General. The Lost Ship in New York just completed its regeneration.","TWN":"這是中將的命令。紐約的失落艦船剛剛復活了。"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SYLVIA_DELTA_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"KYLE_DELTA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L49_1","type":"dialog","speaker":"KYLE_DELTA_NULL_NULL","text":{"KOREA":"그리고 14초 남았습니다.","JPN":"残り14秒です。","ENG":"And you’ve got 14 seconds now.","TWN":"然後妳還有14秒。"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SYLVIA_DELTA_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"KYLE_DELTA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L50_1","type":"dialog","speaker":"SYLVIA_DELTA_NULL_NULL","text":{"KOREA":"아...... 이!! 개████! █████!! ███!!","JPN":"あああ、もう！！　くそ████！　█████！！　███！！","ENG":"Ugh... Why you little... Son of a ████! █████!! ███!!","TWN":"啊……你這！狗████！ █████！!  ███！ !"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SYLVIA_DELTA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"KYLE_DELTA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L3_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":".......","JPN":"……","ENG":".......","TWN":"……"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"JOOSHIYOON_FENRIR_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L4_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_NULL_NULL","text":{"KOREA":".......","JPN":"……","ENG":".......","TWN":"……"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"JOOSHIYOON_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L6_1","type":"dialog","speaker":"SYLVIA_DELTA_NULL_NULL","text":{"KOREA":"들었지?! 나 지금 나가봐야 하니까 명심하라고, 코핀 친구들!","JPN":"聞こえたよね！？\\nアタシは今から出動だから、肝に銘じておいてね。コフィンのみんな！","ENG":"Hear that? I've gotta run. But don't forget my dear Coffineers!","TWN":"……你們聽到了吧？我現在得出動了，所以你們記好了，科芬的朋友們。"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SYLVIA_DELTA_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"SYLVIA_DELTA_NULL_NULL","text":{"KOREA":"사태 해결에 도움이 된다고 해서 지푸라기라도 잡는 심정으로 무리해서 정보를 찾아 준 거야.","JPN":"事件収拾に役立つっていうから、藁にもすがる気持ちで情報をかき集めてあげたのよ。","ENG":"I pulled every string there is to pull to get you this intel since you said it might help. I’m grasping at straws here.","TWN":"如果對解決這次危機有幫助，就算是最後一根稻草也不能放棄，要盡全力地找到資料。"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SYLVIA_DELTA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"SYLVIA_DELTA_NULL_NULL","text":{"KOREA":"그나마 이쪽 사정을 잘 알면서 만일의 경우에 리플레이서 간부급을 상대할 수 있는 태스크포스는 너희 코핀 컴퍼니가 유일하니까.","JPN":"こっちの事情を十分承知の上で、いざという時にリプレイサー幹部級にも対応できるタスクフォースは、コフィンカンパニーだけだからね。","ENG":"Coffin Company is the only TASKFORCE that has the slightest idea of what’s going on... and capable of handling Replacer officers if it comes to that.","TWN":"儘管你們不知道我們這邊情況，但萬一遇到克隆集團的幹部，也只有你們科芬公司可以與之抗衡。"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SYLVIA_DELTA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"SYLVIA_DELTA_NULL_NULL","text":{"KOREA":"그러니까 모든 수단을 동원해서!","JPN":"だから、あらゆる手段を使い倒して！","ENG":"So do whatever you must!","TWN":"所以，要使出所有的手段。"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SYLVIA_DELTA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"SYLVIA_DELTA_NULL_NULL","text":{"KOREA":"어떤 출혈을 감수하더라도!","JPN":"どんな犠牲を払ってでも！","ENG":"No matter the risk!","TWN":"不管會付出什麼樣的代價。"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SYLVIA_DELTA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"SYLVIA_DELTA_NULL_NULL","text":{"KOREA":"반드시 놈들의 본거지를 찾아서 이 사태를 해결해야 해!","JPN":"必ずやつらの本拠地を突き止めて、この事態を収拾するのよ！","ENG":"You’ve got to find their hideout and resolve this once and for all!","TWN":"一定要找到那些傢伙的根據地，解決這次危機！"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SYLVIA_DELTA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"SYLVIA_DELTA_NULL_NULL","text":{"KOREA":"알아들었어? 꼭! 꼭이야!!","JPN":"わかった？　絶対！　絶対よ！！","ENG":"Got that? You must! No matter what!","TWN":"明白了嗎？一定要找到！一定！！"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SYLVIA_DELTA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"HILDE_FENRIR_NULL_NULL","text":{"KOREA":"......노력해 보지.","JPN":"……努力する。","ENG":"We’ll... try.","TWN":"……我們會盡力的。"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HILDE_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"SYLVIA_DELTA_NULL_NULL","text":{"KOREA":"노력이 아니라 결과를 가져 오라고!","JPN":"努力だけで終わらせないで、結果をもたらすの！","ENG":"Don’t just try! Bring me results!","TWN":"我不要盡力，我要看到結果！"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SYLVIA_DELTA_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"KYLE_DELTA_NULL_NULL","text":{"KOREA":"5초 남았습니다. 통신망 끊습니다.","JPN":"残り5秒。通信を切ります。","ENG":"5 seconds. I’m ending your call now.","TWN":"只剩5秒。我要切斷妳的通信網路了。"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SYLVIA_DELTA_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"KYLE_DELTA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L18_1","type":"dialog","speaker":"SYLVIA_DELTA_NULL_NULL","text":{"KOREA":"잠깐! 야!","JPN":"ちょっと！　おい！","ENG":"Wait! Hey!","TWN":"等等！喂！"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SYLVIA_DELTA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"KYLE_DELTA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L19_1","type":"dialog","speaker":"SYLVIA_DELTA_NULL_NULL","text":{"KOREA":"너 이 ████! ██! ███████!","JPN":"この████！　█████！　███！","ENG":"You little ████! ██! ███████!","TWN":"你這個████！ ██！ ███████！"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SYLVIA_DELTA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"KYLE_DELTA_NULL_NULL","face":"UNIT_IDLE"}}}}]`);export{e as default};